Elasticsearch는 전문 검색과 분석에 특화된 엔진입니다.

```python
# ═══ Elasticsearch 8.x ═══
from elasticsearch import AsyncElasticsearch

es = AsyncElasticsearch(
    "https://localhost:9200",
    api_key="xxx",
)

# ═══ 1. 인덱스 생성 (한국어 형태소 분석) ═══
await es.indices.create(
    index="posts",
    body={
        "settings": {
            "analysis": {
                "analyzer": {
                    "korean": {
                        "type": "custom",
                        "tokenizer": "nori_tokenizer",  # 한국어 형태소
                        "filter": [
                            "nori_part_of_speech",
                            "lowercase",
                        ],
                    },
                },
            },
        },
        "mappings": {
            "properties": {
                "title": {
                    "type": "text",
                    "analyzer": "korean",
                    "fields": {
                        "keyword": {"type": "keyword"},  # 정렬/집계용
                    },
                },
                "content": {"type": "text", "analyzer": "korean"},
                "tags": {"type": "keyword"},
                "author": {"type": "keyword"},
                "created_at": {"type": "date"},
                "view_count": {"type": "integer"},
                "embedding": {
                    "type": "dense_vector",  # 벡터 검색
                    "dims": 1024,
                    "index": True,
                    "similarity": "cosine",
                },
            },
        },
    },
)

# ═══ 2. 문서 색인 ═══
await es.index(
    index="posts",
    id="1",
    document={
        "title": "파이썬 비동기 프로그래밍",
        "content": "asyncio를 활용한 효율적인 서버 개발...",
        "tags": ["python", "asyncio"],
        "author": "홍길동",
        "created_at": "2025-04-20T10:00:00Z",
        "view_count": 150,
    },
)

# 벌크 색인 (대량)
from elasticsearch.helpers import async_bulk

actions = [
    {
        "_index": "posts",
        "_id": str(post["id"]),
        "_source": post,
    }
    for post in posts
]
await async_bulk(es, actions, chunk_size=500)

# ═══ 3. 검색 ═══
# 기본 검색
result = await es.search(
    index="posts",
    body={
        "query": {
            "multi_match": {
                "query": "파이썬 비동기",
                "fields": ["title^3", "content"],  # 제목 3배 가중치
                "type": "best_fields",
            },
        },
        "highlight": {
            "fields": {"title": {}, "content": {}},
            "pre_tags": ["<mark>"],
            "post_tags": ["</mark>"],
        },
        "sort": [
            {"_score": "desc"},
            {"created_at": "desc"},
        ],
        "from": 0,
        "size": 20,
    },
)

# 복합 쿼리 (bool)
result = await es.search(
    index="posts",
    body={
        "query": {
            "bool": {
                "must": [
                    {"multi_match": {"query": "파이썬", "fields": ["title", "content"]}},
                ],
                "filter": [
                    {"term": {"author": "홍길동"}},
                    {"range": {"created_at": {"gte": "2025-01-01"}}},
                    {"terms": {"tags": ["python", "asyncio"]}},
                ],
                "must_not": [
                    {"term": {"status": "deleted"}},
                ],
            },
        },
    },
)

# 자동완성 (Suggest)
result = await es.search(
    index="posts",
    body={
        "suggest": {
            "title_suggest": {
                "prefix": "파이",
                "completion": {
                    "field": "title.suggest",
                    "size": 5,
                    "fuzzy": {"fuzziness": "AUTO"},
                },
            },
        },
    },
)

# ═══ 4. 집계 (Analytics) ═══
result = await es.search(
    index="posts",
    body={
        "size": 0,  # 문서 안 가져옴 (집계만)
        "aggs": {
            "tags_count": {
                "terms": {"field": "tags", "size": 20},
            },
            "monthly_posts": {
                "date_histogram": {
                    "field": "created_at",
                    "calendar_interval": "month",
                },
            },
            "avg_views": {
                "avg": {"field": "view_count"},
            },
        },
    },
)
```

Elasticsearch 적합 사례:
- **전문 검색**: 블로그, 상품, 문서 검색
- **로그 분석**: ELK 스택 (Elasticsearch + Logstash + Kibana)
- **자동완성**: 실시간 검색어 제안
- **분석/집계**: 대시보드 통계

Supabase는 오픈소스 Firebase 대안 (PostgreSQL 기반)입니다.

```typescript
// ═══ 1. Supabase 클라이언트 ═══
import { createClient } from "@supabase/supabase-js";
import type { Database } from "@/types/supabase";  // 자동 생성 타입

const supabase = createClient<Database>(
  process.env.NEXT_PUBLIC_SUPABASE_URL!,
  process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
);

// ═══ 2. CRUD ═══
// 조회
const { data: users, error } = await supabase
  .from("users")
  .select("id, name, email, profile:profiles(bio, avatar_url)")  // JOIN
  .eq("status", "active")
  .order("created_at", { ascending: false })
  .range(0, 19);  // 페이지네이션

// 단일 조회
const { data: user } = await supabase
  .from("users")
  .select("*")
  .eq("id", userId)
  .single();

// 생성
const { data, error } = await supabase
  .from("users")
  .insert({ name: "홍길동", email: "hong@test.com" })
  .select()
  .single();

// 수정
const { data } = await supabase
  .from("users")
  .update({ name: "홍길동2" })
  .eq("id", userId)
  .select()
  .single();

// 삭제
await supabase.from("users").delete().eq("id", userId);

// ═══ 3. 인증 ═══
// 회원가입
const { data, error } = await supabase.auth.signUp({
  email: "hong@test.com",
  password: "securepassword",
  options: {
    data: { name: "홍길동" },  // 사용자 메타데이터
  },
});

// 로그인
const { data } = await supabase.auth.signInWithPassword({
  email: "hong@test.com",
  password: "securepassword",
});

// 소셜 로그인
const { data } = await supabase.auth.signInWithOAuth({
  provider: "google",
  options: { redirectTo: `${location.origin}/auth/callback` },
});

// 현재 사용자
const { data: { user } } = await supabase.auth.getUser();

// 로그아웃
await supabase.auth.signOut();

// ═══ 4. 실시간 구독 ═══
const channel = supabase
  .channel("messages")
  .on(
    "postgres_changes",
    { event: "INSERT", schema: "public", table: "messages", filter: `room_id=eq.${roomId}` },
    (payload) => {
      console.log("새 메시지:", payload.new);
      setMessages((prev) => [...prev, payload.new]);
    },
  )
  .subscribe();

// 구독 해제
supabase.removeChannel(channel);

// ═══ 5. 파일 스토리지 ═══
// 업로드
const { data, error } = await supabase.storage
  .from("avatars")
  .upload(`users/${userId}/avatar.png`, file, {
    cacheControl: "3600",
    upsert: true,
  });

// 공개 URL
const { data: { publicUrl } } = supabase.storage
  .from("avatars")
  .getPublicUrl(`users/${userId}/avatar.png`);

// ═══ 6. Edge Functions ═══
// supabase/functions/hello/index.ts
import { serve } from "https://deno.land/std@0.177.0/http/server.ts";

serve(async (req) => {
  const { name } = await req.json();
  return new Response(
    JSON.stringify({ message: `안녕하세요, ${name}!` }),
    { headers: { "Content-Type": "application/json" } },
  );
});

// 호출
const { data } = await supabase.functions.invoke("hello", {
  body: { name: "홍길동" },
});

// ═══ 7. RLS (Row Level Security) ═══
-- SQL 정책
ALTER TABLE posts ENABLE ROW LEVEL SECURITY;

-- 모든 사용자가 읽기 가능
CREATE POLICY "posts_read" ON posts FOR SELECT USING (true);

-- 본인 게시글만 수정/삭제
CREATE POLICY "posts_write" ON posts FOR ALL
  USING (auth.uid() = user_id);

-- 관리자는 모든 것 가능
CREATE POLICY "admin_all" ON posts FOR ALL
  USING (auth.jwt()->>'role' = 'admin');
```

Supabase vs Firebase:
| 항목 | Supabase | Firebase |
|------|----------|---------|
| DB | PostgreSQL (SQL) | Firestore (NoSQL) |
| 쿼리 | SQL (강력) | 제한적 |
| 오픈소스 | ✅ | ❌ |
| 셀프호스팅 | ✅ | ❌ |
| 실시간 | ✅ | ✅ |
| 인증 | ✅ | ✅ |
| 스토리지 | ✅ | ✅ |
| 가격 | 저렴 | 비쌈 |

Prisma ORM 고급 패턴입니다 (v6 기준).

```typescript
// ═══ 1. 스키마 설계 ═══
// prisma/schema.prisma

generator client {
  provider = "prisma-client-js"
}

datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

model User {
  id            String   @id @default(cuid())
  email         String   @unique
  name          String
  role          Role     @default(USER)
  hashedPassword String?

  // 관계
  posts         Post[]
  comments      Comment[]
  profile       Profile?

  // 타임스탬프
  createdAt     DateTime @default(now())
  updatedAt     DateTime @updatedAt

  // 인덱스
  @@index([email])
  @@index([role, createdAt(sort: Desc)])
  @@map("users")
}

model Post {
  id        String   @id @default(cuid())
  title     String
  content   String
  published Boolean  @default(false)
  viewCount Int      @default(0)
  tags      String[]

  author    User     @relation(fields: [authorId], references: [id], onDelete: Cascade)
  authorId  String
  comments  Comment[]

  createdAt DateTime @default(now())
  updatedAt DateTime @updatedAt

  // 전문 검색 인덱스
  @@index([title, content])
  @@map("posts")
}

enum Role {
  USER
  ADMIN
  EDITOR
}

// ═══ 2. 고급 쿼리 ═══
import { PrismaClient, Prisma } from "@prisma/client";

const prisma = new PrismaClient({
  log: process.env.NODE_ENV === "development" ? ["query", "warn", "error"] : ["error"],
});

// 관계 포함 + 필터 + 정렬 + 페이지네이션
async function getUsers(params: {
  page: number;
  limit: number;
  search?: string;
  role?: Role;
}) {
  const where: Prisma.UserWhereInput = {
    ...(params.search && {
      OR: [
        { name: { contains: params.search, mode: "insensitive" } },
        { email: { contains: params.search, mode: "insensitive" } },
      ],
    }),
    ...(params.role && { role: params.role }),
  };

  const [users, total] = await prisma.$transaction([
    prisma.user.findMany({
      where,
      include: {
        profile: true,
        _count: { select: { posts: true, comments: true } },
      },
      orderBy: { createdAt: "desc" },
      skip: (params.page - 1) * params.limit,
      take: params.limit,
    }),
    prisma.user.count({ where }),
  ]);

  return { users, total, totalPages: Math.ceil(total / params.limit) };
}

// ═══ 3. 트랜잭션 ═══
// Interactive 트랜잭션 (복잡한 로직)
async function transferPoints(fromId: string, toId: string, amount: number) {
  return prisma.$transaction(async (tx) => {
    const sender = await tx.user.findUnique({ where: { id: fromId } });
    if (!sender || sender.points < amount) {
      throw new Error("포인트 부족");
    }

    await tx.user.update({
      where: { id: fromId },
      data: { points: { decrement: amount } },
    });

    await tx.user.update({
      where: { id: toId },
      data: { points: { increment: amount } },
    });

    await tx.pointHistory.create({
      data: { fromId, toId, amount, type: "TRANSFER" },
    });
  });
}

// ═══ 4. 원시 SQL (복잡한 쿼리) ═══
// 타입 안전한 원시 쿼리
const result = await prisma.$queryRaw<{ month: Date; count: bigint }[]>`
  SELECT
    DATE_TRUNC('month', created_at) AS month,
    COUNT(*) AS count
  FROM posts
  WHERE published = true
    AND created_at >= NOW() - INTERVAL '12 months'
  GROUP BY month
  ORDER BY month DESC
`;

// ═══ 5. Middleware (로깅, 소프트 삭제) ═══
// 소프트 삭제 미들웨어
prisma.$use(async (params, next) => {
  // DELETE → UPDATE (deleted_at 설정)
  if (params.action === "delete") {
    params.action = "update";
    params.args.data = { deletedAt: new Date() };
  }

  // findMany → 삭제된 항목 제외
  if (params.action === "findMany" || params.action === "findFirst") {
    if (!params.args.where) params.args.where = {};
    params.args.where.deletedAt = null;
  }

  return next(params);
});

// ═══ 6. 확장 (Extension) ═══
const xprisma = prisma.$extends({
  model: {
    user: {
      async findByEmail(email: string) {
        return prisma.user.findUnique({ where: { email } });
      },
      async softDelete(id: string) {
        return prisma.user.update({
          where: { id },
          data: { deletedAt: new Date() },
        });
      },
    },
  },
  query: {
    $allOperations({ operation, args, query }) {
      const start = performance.now();
      return query(args).finally(() => {
        const duration = performance.now() - start;
        if (duration > 1000) {
          console.warn(`느린 쿼리: ${operation} (${duration.toFixed(0)}ms)`);
        }
      });
    },
  },
});

// 사용
const user = await xprisma.user.findByEmail("hong@test.com");
await xprisma.user.softDelete("user_123");
```

Prisma 핵심:
- `$transaction` → 원자적 작업
- `include` / `select` → 관계 로딩
- `_count` → 관계 카운트 (서브쿼리 자동)
- Middleware → 공통 로직 (로깅, 소프트삭제)
- Extension → 커스텀 메서드 추가
